public class LinearQueue {
    // Storage: Array and pointers
    private int[] arr;
    private int front, rear, capacity;

    public LinearQueue(int size) {
        capacity = size;
        arr = new int[capacity];
        front = 0;
        rear = 0;
    }

    // Process & Storage: Enqueue
    public void enqueue(int item) {
        if (rear == capacity) {
            System.out.println("Queue is full"); // Output
            return;
        }
        arr[rear++] = item; // Storage insert
    }

    // Process: Dequeue
    public int dequeue() {
        if (front == rear) {
            System.out.println("Queue is empty"); // Output
            return -1;
        }
        int item = arr[front++]; // Storage
        return item; // Output
    }
}

import java.util.LinkedList;
import java.util.Queue;

public class StackUsingQueues {
    // Storage: Two queues
    private Queue<Integer> q1 = new LinkedList<>();
    private Queue<Integer> q2 = new LinkedList<>();

    // Process & Storage: Push (making push costly)
    public void push(int x) {
        q2.add(x); // Storage

        // Move all elements from q1 to q2
        while (!q1.isEmpty()) {
            q2.add(q1.poll());
        }

        // Swap queues
        Queue<Integer> temp = q1;
        q1 = q2;
        q2 = temp;
    }

    // Output: Pop
    public int pop() {
        if (q1.isEmpty()) throw new IllegalStateException("Stack empty");
        return q1.poll();
    }
}

import java.util.Stack;

public class QueueUsingStacks {
    // Storage: Two stacks
    private Stack<Integer> inputStack = new Stack<>();
    private Stack<Integer> outputStack = new Stack<>();

    // Process & Storage: Enqueue
    public void enqueue(int x) {
        inputStack.push(x);
    }

    // Process & Output: Dequeue
    public int dequeue() {
        if (outputStack.isEmpty()) {
            while (!inputStack.isEmpty()) {
                outputStack.push(inputStack.pop());
            }
        }
        if (outputStack.isEmpty()) {
            throw new IllegalStateException("Queue empty");
        }
        return outputStack.pop();
    }
}

public class CircularQueue {
    // Storage: Array and pointers
    private int[] queueArray;
    private int front, rear, size, capacity;

    public CircularQueue(int cap) {
        capacity = cap;
        queueArray = new int[capacity];
        front = -1;
        rear = -1;
        size = 0;
    }

    // Process & Storage: Add element
    public boolean enqueue(int value) {
        if (size == capacity) return false; // Full
        if (front == -1) front = 0;

        rear = (rear + 1) % capacity; // Circular increment
        queueArray[rear] = value;
        size++;
        return true;
    }

    // Process & Storage: Remove element
    public int dequeue() {
        if (size == 0) throw new IllegalStateException("Queue empty");

        int value = queueArray[front];
        if (front == rear) {
            front = -1;
            rear = -1;
        } else {
            front = (front + 1) % capacity; // Circular increment
        }
        size--;
        return value; // Output
    }
}

