import java.util.ArrayDeque;

public class DequeDemo {
    public static void runDeque() {
        // Storage: Instantiation of ArrayDeque
        ArrayDeque<Integer> deque = new ArrayDeque<>();

        // Process: Insert operations at both ends
        deque.addFirst(10); // Insert Front
        deque.addLast(20);  // Insert Rear
        deque.addFirst(5);  // Insert Front

        // Output: Print list
        System.out.println("Deque elements: " + deque);

        // Process & Output: Remove operations
        int frontVal = deque.removeFirst(); // Storage: 5
        int rearVal = deque.removeLast();   // Storage: 20

        System.out.println("Removed Front: " + frontVal);
        System.out.println("Removed Rear: " + rearVal);
    }
}
